import { useState } from 'react'
import type { LineItemOut } from '../types/api'
import { formatServiceType } from '../utils/format'
import { ExplanationPanel } from './ExplanationPanel'
import { Money } from './Money'
import { StatusBadge } from './StatusBadge'

type LineItemTableProps = {
  lineItems: LineItemOut[]
  onRaiseDispute?: (lineItem: LineItemOut) => void
  disputingLineItemId?: string | null
}

function canDispute(status: LineItemOut['status']): boolean {
  return status === 'approved' || status === 'denied'
}

export function LineItemTable({
  lineItems,
  onRaiseDispute,
  disputingLineItemId = null,
}: LineItemTableProps) {
  const [selectedId, setSelectedId] = useState<string | null>(
    lineItems[0]?.id ?? null,
  )

  const selected = lineItems.find((li) => li.id === selectedId) ?? null

  return (
    <div className="line-items-layout">
      <div className="table-wrap">
        <table className="data-table">
          <thead>
            <tr>
              <th scope="col">Service</th>
              <th scope="col">Description</th>
              <th scope="col">Charged</th>
              <th scope="col">Status</th>
              <th scope="col">Plan pays</th>
              <th scope="col">Member pays</th>
            </tr>
          </thead>
          <tbody>
            {lineItems.map((li) => {
              const isSelected = li.id === selectedId
              return (
                <tr
                  key={li.id}
                  className={isSelected ? 'data-table__row--selected' : 'data-table__row--clickable'}
                  onClick={() => setSelectedId(li.id)}
                  tabIndex={0}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      e.preventDefault()
                      setSelectedId(li.id)
                    }
                  }}
                  aria-selected={isSelected}
                >
                  <td>
                    <code>{formatServiceType(li.service_type)}</code>
                  </td>
                  <td>{li.service_description}</td>
                  <td>
                    <Money value={li.charged_amount} />
                  </td>
                  <td>
                    <StatusBadge kind="line" value={li.status} />
                  </td>
                  <td>
                    <Money value={li.payable_amount} />
                  </td>
                  <td>
                    <Money value={li.member_responsibility} />
                  </td>
                </tr>
              )
            })}
          </tbody>
        </table>
      </div>

      <aside className="line-item-detail">
        {selected ? (
          <>
            <h3>{selected.service_description}</h3>
            <dl className="detail-grid detail-grid--compact">
              <div>
                <dt>Line item id</dt>
                <dd>
                  <code>{selected.id}</code>
                </dd>
              </div>
              <div>
                <dt>Service type</dt>
                <dd>
                  <code>{selected.service_type}</code>
                </dd>
              </div>
              {selected.preauth_ref && (
                <div>
                  <dt>Preauth ref</dt>
                  <dd>
                    <code>{selected.preauth_ref}</code>
                  </dd>
                </div>
              )}
            </dl>
            {selected.current_decision ? (
              <ExplanationPanel decision={selected.current_decision} />
            ) : (
              <p className="empty-note">No decision yet — still being reviewed.</p>
            )}
            {onRaiseDispute && canDispute(selected.status) && (
              <div className="line-item-detail__actions">
                <button
                  type="button"
                  className="button"
                  disabled={disputingLineItemId === selected.id}
                  onClick={() => onRaiseDispute(selected)}
                >
                  {disputingLineItemId === selected.id ? 'Submitting…' : 'Raise dispute'}
                </button>
              </div>
            )}
            {selected.status === 'needs_review' && (
              <p className="hint">
                This line is with our team for review. Human evaluation is pending.
              </p>
            )}
          </>
        ) : (
          <p className="empty-note">Select a line item to view its decision.</p>
        )}
      </aside>
    </div>
  )
}

import { useEffect, useState } from 'react'
import { Link, useParams } from 'react-router-dom'
import { ApiError, fileDispute, getClaim } from '../api/client'
import { AuditTimeline } from '../components/AuditTimeline'
import { ErrorState } from '../components/ErrorState'
import { LineItemTable } from '../components/LineItemTable'
import { LoadingState } from '../components/LoadingState'
import { Money } from '../components/Money'
import { StatusBadge } from '../components/StatusBadge'
import type { ClaimDetailOut, LineItemOut } from '../types/api'
import { formatDate, formatDateTime } from '../utils/format'

export function ClaimDetailPage() {
  const { claimId } = useParams<{ claimId: string }>()
  const [claim, setClaim] = useState<ClaimDetailOut | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<{ message: string; notFound: boolean } | null>(null)
  const [disputeTarget, setDisputeTarget] = useState<LineItemOut | null>(null)
  const [disputeReason, setDisputeReason] = useState('')
  const [disputingLineItemId, setDisputingLineItemId] = useState<string | null>(null)
  const [disputeError, setDisputeError] = useState<string | null>(null)
  const [disputeSuccess, setDisputeSuccess] = useState<string | null>(null)

  useEffect(() => {
    if (!claimId) return
    const controller = new AbortController()
    setLoading(true)
    setError(null)

    getClaim(claimId)
      .then(setClaim)
      .catch((err: unknown) => {
        if (controller.signal.aborted) return
        if (err instanceof ApiError && err.status === 404) {
          setError({ message: err.message, notFound: true })
          return
        }
        setError({
          message: err instanceof Error ? err.message : String(err),
          notFound: false,
        })
      })
      .finally(() => {
        if (!controller.signal.aborted) setLoading(false)
      })

    return () => controller.abort()
  }, [claimId])

  async function handleDisputeSubmit() {
    if (!disputeTarget) return
    const reason = disputeReason.trim()
    if (!reason) {
      setDisputeError('Please describe why you are disputing this decision.')
      return
    }

    setDisputeError(null)
    setDisputingLineItemId(disputeTarget.id)
    try {
      const updated = await fileDispute(disputeTarget.id, reason)
      setClaim(updated)
      setDisputeTarget(null)
      setDisputeReason('')
      setDisputeSuccess(
        'Your dispute has been raised with our team. A human reviewer will evaluate it.',
      )
    } catch (err) {
      if (err instanceof ApiError) {
        setDisputeError(err.message)
      } else {
        setDisputeError(err instanceof Error ? err.message : String(err))
      }
    } finally {
      setDisputingLineItemId(null)
    }
  }

  if (!claimId) {
    return (
      <ErrorState
        title="Missing claim id"
        message="No claim id in the URL."
        showBackendHint={false}
        footer={
          <p className="hint">
            <Link to="/">← Back to claims</Link>
          </p>
        }
      />
    )
  }

  if (loading) return <LoadingState message="Loading claim…" />
  if (error) {
    return (
      <ErrorState
        title={error.notFound ? 'Claim not found' : undefined}
        message={error.message}
        showBackendHint={!error.notFound}
        footer={
          error.notFound ? (
            <p className="hint">
              <Link to="/">← Back to claims</Link>
            </p>
          ) : undefined
        }
      />
    )
  }
  if (!claim) {
    return (
      <ErrorState
        title="Claim not found"
        message="This claim could not be loaded."
        showBackendHint={false}
        footer={
          <p className="hint">
            <Link to="/">← Back to claims</Link>
          </p>
        }
      />
    )
  }

  return (
    <div className="page">
      <Link to="/" className="back-link">
        ← Back to claims
      </Link>

      <div className="page-header">
        <div>
          <h1 className="page-title">
            Claim <code>{claim.id}</code>
          </h1>
          <p className="page-subtitle">
            {claim.member_name} · {claim.provider_name}
          </p>
        </div>
        <StatusBadge kind="claim" value={claim.adjudication_state} />
      </div>

      {disputeSuccess && (
        <div className="banner banner--success" role="status">
          {disputeSuccess}
        </div>
      )}

      <section className="card summary-card">
        <h2>Summary</h2>
        <dl className="detail-grid">
          <div>
            <dt>Member</dt>
            <dd>
              {claim.member_name} (<code>{claim.member_id}</code>)
            </dd>
          </div>
          <div>
            <dt>Provider</dt>
            <dd>{claim.provider_name}</dd>
          </div>
          <div>
            <dt>Service date</dt>
            <dd>{formatDate(claim.service_date)}</dd>
          </div>
          <div>
            <dt>Submitted</dt>
            <dd>{formatDateTime(claim.submitted_at)}</dd>
          </div>
          <div>
            <dt>Paid</dt>
            <dd>{claim.paid_at ? formatDateTime(claim.paid_at) : 'Not paid'}</dd>
          </div>
          <div>
            <dt>Total charged</dt>
            <dd>
              <Money value={claim.totals.charged} />
            </dd>
          </div>
          <div>
            <dt>Plan pays</dt>
            <dd>
              <Money value={claim.totals.payable} />
            </dd>
          </div>
          <div>
            <dt>Member responsibility</dt>
            <dd>
              <Money value={claim.totals.member_responsibility} />
            </dd>
          </div>
        </dl>
      </section>

      <section className="card">
        <h2>Line items &amp; decisions</h2>
        <p className="section-hint">Click a row to see why this line was approved, denied, or flagged.</p>
        <LineItemTable
          lineItems={claim.line_items}
          onRaiseDispute={(lineItem) => {
            setDisputeSuccess(null)
            setDisputeError(null)
            setDisputeReason('')
            setDisputeTarget(lineItem)
          }}
          disputingLineItemId={disputingLineItemId}
        />
      </section>

      <section className="card">
        <h2>Audit timeline</h2>
        <AuditTimeline events={claim.audit_events} />
      </section>

      {disputeTarget && (
        <div className="modal-backdrop" role="presentation" onClick={() => setDisputeTarget(null)}>
          <div
            className="modal card"
            role="dialog"
            aria-labelledby="dispute-dialog-title"
            onClick={(e) => e.stopPropagation()}
          >
            <h2 id="dispute-dialog-title">Raise dispute</h2>
            <p className="section-hint">
              Disputing <strong>{disputeTarget.service_description}</strong>. We will route this
              to our team for human review.
            </p>
            <label className="field">
              <span>Reason</span>
              <textarea
                rows={4}
                value={disputeReason}
                onChange={(e) => setDisputeReason(e.target.value)}
                placeholder="Explain why you disagree with this coverage decision…"
              />
            </label>
            {disputeError && (
              <div className="form-error" role="alert">
                {disputeError}
              </div>
            )}
            <div className="form-actions">
              <button
                type="button"
                className="button button--ghost"
                onClick={() => setDisputeTarget(null)}
                disabled={disputingLineItemId !== null}
              >
                Cancel
              </button>
              <button
                type="button"
                className="button button--primary"
                disabled={disputingLineItemId !== null}
                onClick={() => void handleDisputeSubmit()}
              >
                {disputingLineItemId ? 'Submitting…' : 'Submit dispute'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

